sql:
SELECT AVG(contribution_score) AS average_contribution
FROM project_members
WHERE project_id = 1;

SELECT influence_score
FROM network_metrics
ORDER BY influence_score DESC;

SELECT polarity_normalized
FROM network_metrics
WHERE connections > (
  SELECT AVG(connections) 
  FROM network_metrics
);

SELECT COUNT(*) AS total_chat_communications
FROM communications
WHERE communication_type = 'chat' AND sentiment_score > 0;

external_knowledge:
; NULL end_date in project_members table implies the employee is still active in the project; 
; Ongoing projects refers to those that have not yet ended, assuming no specific end date information is available for completed projects; 
; Engagement statistics include average engagement score and number of projects involved; 
; Sentiment statistics refer to the average sentiment score from communication content.
